pragma solidity 0.7.6;
pragma abicoder v2;

import {SafeMath} from '@openzeppelin/contracts/math/SafeMath.sol';

import {IVotingPowerStrategy} from '../../interfaces/governance/IVotingPowerStrategy.sol';
import {IKyberGovernance} from '../../interfaces/governance/IKyberGovernance.sol';
import {IKyberStaking} from '../../interfaces/staking/IKyberStaking.sol';
import {EpochUtils} from '../../misc/EpochUtils.sol';


contract EpochVotingPowerStrategy is IVotingPowerStrategy, EpochUtils {
  using SafeMath for uint256;

  uint256 public constant MAX_PROPOSAL_PER_EPOCH = 10;
  IKyberStaking public immutable staking;
  IKyberGovernance public immutable governance;

  mapping(uint256 => uint256[]) internal epochProposals;


  constructor(IKyberGovernance _governance, IKyberStaking _staking)
    EpochUtils(_staking.epochPeriodInSeconds(), _staking.firstEpochStartTime())
  {
    staking = _staking;
    governance = _governance;
  }

  modifier onlyStaking() {
    require(msg.sender == address(staking), 'only staking');
    _;
  }

  modifier onlyGovernance() {
    require(msg.sender == address(governance), 'only governance');
    _;
  }


  function handleProposalCreation(
    uint256 proposalId,
    uint256 startTime,
    uint256 
  ) external override onlyGovernance {
    uint256 epoch = getEpochNumber(startTime);

    epochProposals[epoch].push(proposalId);
  }



  function handleProposalCancellation(uint256 proposalId) external override onlyGovernance {
    IKyberGovernance.ProposalWithoutVote memory proposal = governance.getProposalById(proposalId);
    uint256 epoch = getEpochNumber(proposal.startTime);

    uint256[] storage proposalIds = epochProposals[epoch];
    for (uint256 i = 0; i < proposalIds.length; i++) {
      if (proposalIds[i] == proposalId) {

        proposalIds[i] = proposalIds[proposalIds.length - 1];
        proposalIds.pop();
        break;
      }
    }
  }


  function handleVote(
    address voter,
    uint256, 
    uint256 
  ) external override onlyGovernance returns (uint256 votingPower) {
    (uint256 stake, uint256 dStake, address representative) = staking
      .initAndReturnStakerDataForCurrentEpoch(voter);
    return representative == voter ? stake.add(dStake) : dStake;
  }



  function handleWithdrawal(
    address user,
    uint256 
  ) external override onlyStaking {
    uint256 currentEpoch = getCurrentEpochNumber();
    (uint256 stake, uint256 dStake, address representative) = staking.getStakerData(
      user,
      currentEpoch
    );
    uint256 votingPower = representative == user ? stake.add(dStake) : dStake;
    governance.handleVotingPowerChanged(user, votingPower, epochProposals[currentEpoch]);
  }


  function getVotingPower(address voter, uint256 timestamp)
    external
    override
    view
    returns (uint256 votingPower)
  {
    uint256 currentEpoch = getEpochNumber(timestamp);
    (uint256 stake, uint256 dStake, address representative) = staking.getStakerData(
      voter,
      currentEpoch
    );
    votingPower = representative == voter ? stake.add(dStake) : dStake;
  }


  function validateProposalCreation(uint256 startTime, uint256 endTime)
    external
    override
    view
    returns (bool)
  {

    if (startTime < block.timestamp) {
      return false;
    }
    uint256 startEpoch = getEpochNumber(startTime);

    if (startEpoch != getEpochNumber(endTime)) {
      return false;
    }

    if (startEpoch > getCurrentEpochNumber().add(1)) {
      return false;
    }

    if (epochProposals[startEpoch].length >= MAX_PROPOSAL_PER_EPOCH) {
      return false;
    }
    return true;
  }

  function getMaxVotingPower() external override view returns (uint256) {
    return staking.kncToken().totalSupply();
  }

  function getListProposalIds(uint256 epoch) external view returns (uint256[] memory proposalIds) {
    return epochProposals[epoch];
  }
}

pragma solidity ^0.8.2;

import "../interfaces/IUniswapV2Router.sol";
import "../interfaces/ITradeFarming.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";
import "@openzeppelin/contracts/access/Ownable.sol";




contract TradeFarming is ITradeFarming, Ownable {



    IUniswapV2Router01 routerContract;

    IERC20 tokenContract;

    IERC20 rewardToken;


    using EnumerableSet for EnumerableSet.UintSet;

    using SafeERC20 for IERC20;






    mapping(uint256 => uint256) public previousVolumes;


    mapping(address => mapping(uint256 => uint256)) public volumeRecords;


    mapping(uint256 => uint256) public dailyVolumes;

    mapping(uint256 => uint256) public dailyRewards;


    mapping(address => EnumerableSet.UintSet) private tradedDays;




    uint256 public totalRewardBalance = 0;

    uint256 public totalDays;

    uint256 public immutable deployTime;


    uint256 private previousDay;

    uint256 public lastAddedDay;

    address private WETH;


    uint256 constant PRECISION = 1e18;

    uint256 immutable UP_VOLUME_CHANGE_LIMIT;
    uint256 immutable DOWN_VOLUME_CHANGE_LIMIT;




    event RewardClaimed(address _user, uint256 _amount);




    constructor(
        address _routerAddress,
        address _tokenAddress,
        address _rewardAddress,
        uint256 _previousVolume,
        uint256 _previousDay,
        uint256 _totalDays,
        uint256 _upLimit,
        uint256 _downLimit
    ) {
        require(
            _routerAddress != address(0) && _tokenAddress != address(0) && _rewardAddress != address(0),
            "[] Addresses can not be 0 address."
        );

        deployTime = block.timestamp;
        routerContract = IUniswapV2Router01(_routerAddress);
        tokenContract = IERC20(_tokenAddress);
        rewardToken = IERC20(_rewardAddress);
        previousVolumes[0] = _previousVolume;
        previousDay = _previousDay;
        totalDays = _totalDays;
        WETH = routerContract.WETH();
        UP_VOLUME_CHANGE_LIMIT = (PRECISION * _upLimit) / 100;
        DOWN_VOLUME_CHANGE_LIMIT = (PRECISION * _downLimit) / 100;
    }




    function depositRewardTokens(uint256 amount) external onlyOwner {
        totalRewardBalance += amount;
        rewardToken.safeTransferFrom(msg.sender, address(this), amount);
    }


    function withdrawRewardTokens(uint256 amount) external onlyOwner {
        require(
            totalRewardBalance >= amount,
            "[withdrawRewardTokens] Not enough balance!"
        );
        totalRewardBalance -= amount;
        rewardToken.safeTransfer(msg.sender, amount);
    }


    function changeTotalDays(uint256 newTotalDays) external onlyOwner {
        totalDays = newTotalDays;
    }




    function claimAllRewards() external virtual override {

        if (lastAddedDay + 1 <= calcDay() && lastAddedDay != totalDays) {
            addNextDaysToAverage();
        }

        uint256 totalRewardOfUser = 0;
        uint256 rewardRate = PRECISION;

        uint256 len = tradedDays[msg.sender].length();
        if(tradedDays[msg.sender].contains(lastAddedDay)) len -= 1;

        uint256[] memory _removeDays = new uint256[](len);

        for (uint256 i = 0; i < len; i++) {
            if (tradedDays[msg.sender].at(i) < lastAddedDay) {

                rewardRate = muldiv(
                    volumeRecords[msg.sender][tradedDays[msg.sender].at(i)],
                    PRECISION,
                    dailyVolumes[tradedDays[msg.sender].at(i)]
                );

                totalRewardOfUser += muldiv(
                    rewardRate,
                    dailyRewards[tradedDays[msg.sender].at(i)],
                    PRECISION
                );
                _removeDays[i] = tradedDays[msg.sender].at(i);
            }
        }


        for (uint256 i = 0; i < len; i++) {
            require(tradedDays[msg.sender].remove(_removeDays[i]), "[claimAllRewards] Unsuccessful set operation");
        }

        require(totalRewardOfUser > 0, "[claimAllRewards] No reward!");
        rewardToken.safeTransfer(msg.sender, totalRewardOfUser);


        emit RewardClaimed(msg.sender, totalRewardOfUser);
    }


    function isCalculated() external view returns (bool) {
        return (!(lastAddedDay + 1 <= calcDay() && lastAddedDay != totalDays) ||
            lastAddedDay == totalDays);
    }


    function calculateUserRewards() external view returns (uint256) {
        uint256 totalRewardOfUser = 0;
        uint256 rewardRate = PRECISION;
        for (uint256 i = 0; i < tradedDays[msg.sender].length(); i++) {
            if (tradedDays[msg.sender].at(i) < lastAddedDay) {
                rewardRate = muldiv(
                    volumeRecords[msg.sender][tradedDays[msg.sender].at(i)],
                    PRECISION,
                    dailyVolumes[tradedDays[msg.sender].at(i)]
                );
                totalRewardOfUser += muldiv(
                    rewardRate,
                    dailyRewards[tradedDays[msg.sender].at(i)],
                    PRECISION
                );
            }
        }
        return totalRewardOfUser;
    }


    function calculateDailyUserReward(uint256 day)
        external
        view
        returns (uint256)
    {
        uint256 rewardOfUser = 0;
        uint256 rewardRate = PRECISION;

        if (tradedDays[msg.sender].contains(day)) {
            rewardRate = muldiv(
                volumeRecords[msg.sender][day],
                PRECISION,
                dailyVolumes[day]
            );
            uint256 dailyReward;
            if (day < lastAddedDay) {
                dailyReward = dailyRewards[day];
            } else if (day == lastAddedDay) {
                uint256 volumeChange = calculateDayVolumeChange(lastAddedDay);
                if (volumeChange > UP_VOLUME_CHANGE_LIMIT) {
                    volumeChange = UP_VOLUME_CHANGE_LIMIT;
                } else if (volumeChange == 0) {
                    volumeChange = 0;
                } else if (volumeChange < DOWN_VOLUME_CHANGE_LIMIT) {
                    volumeChange = DOWN_VOLUME_CHANGE_LIMIT;
                }
                dailyReward = muldiv(
                    totalRewardBalance / (totalDays - lastAddedDay),
                    volumeChange,
                    PRECISION
                );
            }
            rewardOfUser += muldiv(rewardRate, dailyReward, PRECISION);
        }

        return rewardOfUser;
    }




    function getAmountsOut(uint256 amountIn, address[] calldata path)
        external
        view
        returns (uint256[] memory amounts)
    {
        return routerContract.getAmountsOut(amountIn, path);
    }


    function getAmountsIn(uint256 amountOut, address[] calldata path)
        external
        view
        returns (uint256[] memory amounts)
    {
        return routerContract.getAmountsIn(amountOut, path);
    }




    function swapExactETHForTokens(
        uint256 amountOutMin,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external payable virtual override returns (uint256[] memory out) {

        require(path[0] == WETH, "[swapExactETHForTokens] Invalid path!");
        require(
            path[path.length - 1] == address(tokenContract),
            "[swapExactETHForTokens] Invalid path!"
        );

        require(msg.value > 0, "[swapExactETHForTokens] Not a msg.value!");


        if (
            !tradedDays[msg.sender].contains(calcDay()) && calcDay() < totalDays
        ) require(tradedDays[msg.sender].add(calcDay()), "[swapExactETHForTokens] Unsuccessful set operation");


        out = routerContract.swapExactETHForTokens{value: msg.value}(
            amountOutMin,
            path,
            to,
            deadline
        );

        if (lastAddedDay != totalDays) tradeRecorder(out[out.length - 1]);
    }



    function swapETHForExactTokens(
        uint256 amountOut,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external payable virtual override returns (uint256[] memory) {

        require(path[0] == WETH, "[swapExactETHForTokens] Invalid path!");
        require(
            path[path.length - 1] == address(tokenContract),
            "[swapExactETHForTokens] Invalid path!"
        );


        uint256 volume = routerContract.getAmountsIn(amountOut, path)[0];
        require(
            msg.value >= volume,
            "[swapETHForExactTokens] Not enough msg.value!"
        );


        if (
            !tradedDays[msg.sender].contains(calcDay()) && calcDay() < totalDays
        ) require(tradedDays[msg.sender].add(calcDay()), "[swapETHForExactTokens] Unsuccessful set operation");


        if (lastAddedDay != totalDays) tradeRecorder(amountOut);

        if (msg.value > volume)
            payable(msg.sender).transfer(msg.value - volume);

        return
            routerContract.swapETHForExactTokens{value: volume}(
                amountOut,
                path,
                to,
                deadline
            );
    }


    function swapExactTokensForETH(
        uint256 amountIn,
        uint256 amountOutMin,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external virtual override returns (uint256[] memory) {

        require(
            path[path.length - 1] == WETH,
            "[swapExactETHForTokens] Invalid path!"
        );
        require(
            path[0] == address(tokenContract),
            "[swapExactETHForTokens] Invalid path!"
        );


        if (
            !tradedDays[msg.sender].contains(calcDay()) && calcDay() < totalDays
        ) require(tradedDays[msg.sender].add(calcDay()), "[swapExactTokensForETH] Unsuccessful set operation");
        tokenContract.safeTransferFrom(msg.sender, address(this), amountIn);


        tokenContract.safeIncreaseAllowance(address(routerContract), amountIn);


        if (lastAddedDay != totalDays) tradeRecorder(amountIn);

        return
            routerContract.swapExactTokensForETH(
                amountIn,
                amountOutMin,
                path,
                to,
                deadline
            );
    }


    function swapTokensForExactETH(
        uint256 amountOut,
        uint256 amountInMax,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external virtual override returns (uint256[] memory out) {

        require(
            path[path.length - 1] == WETH,
            "[swapExactETHForTokens] Invalid path!"
        );
        require(
            path[0] == address(tokenContract),
            "[swapExactETHForTokens] Invalid path!"
        );


        if (
            !tradedDays[msg.sender].contains(calcDay()) && calcDay() < totalDays
        ) require(tradedDays[msg.sender].add(calcDay()), "[swapTokensForExactETH] Unsuccessful set operation");
        tokenContract.safeTransferFrom(
            msg.sender,
            address(this),
            routerContract.getAmountsIn(amountOut, path)[0]
        );


        tokenContract.safeIncreaseAllowance(
            address(routerContract),
            amountInMax
        );


        out = routerContract.swapTokensForExactETH(
            amountOut,
            amountInMax,
            path,
            to,
            deadline
        );

        if (lastAddedDay != totalDays) tradeRecorder(out[0]);


        tokenContract.safeApprove(address(routerContract), 0);
    }




    function calcDay() public view returns (uint256) {
        return (block.timestamp - deployTime) / 1 days;
    }




    function tradeRecorder(uint256 volume) private {

        if (calcDay() < totalDays) {
            volumeRecords[msg.sender][calcDay()] += volume;
            dailyVolumes[calcDay()] += volume;
        }


        if (lastAddedDay + 1 <= calcDay() && lastAddedDay != totalDays) {
            addNextDaysToAverage();
        }
    }


    function calculateDayVolumeChange(uint256 day)
        private
        view
        returns (uint256)
    {
        return muldiv(dailyVolumes[day], PRECISION, previousVolumes[day]);
    }


    function addNextDaysToAverage() private {
        uint256 _cd = calcDay();

        uint256 _pd = previousDay + lastAddedDay + 1;
        assert(lastAddedDay + 1 <= _cd);

        previousVolumes[lastAddedDay + 1] =
            muldiv(previousVolumes[lastAddedDay], (_pd - 1), _pd) +
            dailyVolumes[lastAddedDay] /
            _pd;

        uint256 volumeChange = calculateDayVolumeChange(lastAddedDay);

        if (volumeChange > UP_VOLUME_CHANGE_LIMIT) {
            volumeChange = UP_VOLUME_CHANGE_LIMIT;
        } else if (volumeChange == 0) {
            volumeChange = 0;
        } else if (volumeChange < DOWN_VOLUME_CHANGE_LIMIT) {
            volumeChange = DOWN_VOLUME_CHANGE_LIMIT;
        }


        if (lastAddedDay == totalDays - 1 && volumeChange > PRECISION) {
            dailyRewards[lastAddedDay] = totalRewardBalance;
        } else {
            dailyRewards[lastAddedDay] = muldiv(
                (totalRewardBalance / (totalDays - lastAddedDay)),
                volumeChange,
                PRECISION
            );
        }
        totalRewardBalance = totalRewardBalance - dailyRewards[lastAddedDay];


        lastAddedDay += 1;


        if (lastAddedDay + 1 <= _cd && lastAddedDay != totalDays)
            addNextDaysToAverage();
    }


    function muldiv(
        uint256 a,
        uint256 b,
        uint256 denominator
    ) private pure returns (uint256 result) {
        require(denominator > 0);

        uint256 prod0;
        uint256 prod1;
        assembly {
            let mm := mulmod(a, b, not(0))
            prod0 := mul(a, b)
            prod1 := sub(sub(mm, prod0), lt(mm, prod0))
        }

        if (prod1 == 0) {
            assembly {
                result := div(prod0, denominator)
            }
            return result;
        }
        require(prod1 < denominator);
        uint256 remainder;
        assembly {
            remainder := mulmod(a, b, denominator)
        }
        assembly {
            prod1 := sub(prod1, gt(remainder, prod0))
            prod0 := sub(prod0, remainder)
        }

        uint256 twos = denominator & (~denominator + 1);
        assembly {
            denominator := div(denominator, twos)
        }

        assembly {
            prod0 := div(prod0, twos)
        }

        assembly {
            twos := add(div(sub(0, twos), twos), 1)
        }
        prod0 |= prod1 * twos;

        uint256 inv = (3 * denominator) ^ 2;

        inv *= 2 - denominator * inv;
        inv *= 2 - denominator * inv;
        inv *= 2 - denominator * inv;
        inv *= 2 - denominator * inv;
        inv *= 2 - denominator * inv;
        inv *= 2 - denominator * inv;

        result = prod0 * inv;
        return result;
    }
}

pragma solidity ^0.7.6;
pragma abicoder v2;

import "hardhat/console.sol";





import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

import "./lib/math/MathUtils.sol";

import "./Governed.sol";
import "./IController.sol";
import "./oracle/IYieldOraclelizable.sol";
import "./ISmartYield.sol";

import "./IProvider.sol";

import "./model/IBondModel.sol";
import "./oracle/IYieldOracle.sol";
import "./IBond.sol";
import "./JuniorToken.sol";

contract SmartYield is
    JuniorToken,
    ISmartYield
{
    using SafeMath for uint256;


    address public controller;


    address public pool;


    address public seniorBond; 


    address public juniorBond; 


    uint256 public underlyingLiquidatedJuniors;


    uint256 public tokensInJuniorBonds;


    uint256 public seniorBondId;


    uint256 public juniorBondId;


    uint256 public juniorBondsMaturitiesPrev;

    uint256[] public juniorBondsMaturities;



    mapping(uint256 => JuniorBondsAt) public juniorBondsMaturingAt;



    mapping(uint256 => SeniorBond) public seniorBonds;



    mapping(uint256 => JuniorBond) public juniorBonds;



    SeniorBond public abond;

    bool public _setup;

    constructor(
      string memory name_,
      string memory symbol_
    )
      JuniorToken(name_, symbol_)
    {}

    function setup(
      address controller_,
      address pool_,
      address seniorBond_,
      address juniorBond_
    )
      external
    {
        require(
          false == _setup,
          "SY: already setup"
        );

        controller = controller_;
        pool = pool_;
        seniorBond = seniorBond_;
        juniorBond = juniorBond_;

        _setup = true;
    }




    function buyTokens(
      uint256 underlyingAmount_,
      uint256 minTokens_,
      uint256 deadline_
    )
      external override
    {
        _beforeProviderOp();

        require(
          false == IController(controller).PAUSED_BUY_JUNIOR_TOKEN(),
          "SY: buyTokens paused"
        );

        require(
          this.currentTime() <= deadline_,
          "SY: buyTokens deadline"
        );

        uint256 fee = MathUtils.fractionOf(underlyingAmount_, IController(controller).FEE_BUY_JUNIOR_TOKEN());
        uint256 getsTokens = (underlyingAmount_ - fee) * 1e18 / this.price();

        require(
          getsTokens >= minTokens_,
          "SY: buyTokens minTokens"
        );



        IProvider(pool)._takeUnderlying(msg.sender, underlyingAmount_);
        IProvider(pool)._depositProvider(underlyingAmount_, fee);
        _mint(msg.sender, getsTokens);
    }


    function sellTokens(
      uint256 tokenAmount_,
      uint256 minUnderlying_,
      uint256 deadline_
    )
      external override
    {
        _beforeProviderOp();

        require(
          this.currentTime() <= deadline_,
          "SY: sellTokens deadline"
        );


        uint256 debtShare = tokenAmount_ * 1e18 / totalSupply();

        uint256 toPay = (tokenAmount_ * this.price() - this.abondDebt() * debtShare) / 1e18;

        require(
          toPay >= minUnderlying_,
          "SY: sellTokens minUnderlying"
        );



        _burn(msg.sender, tokenAmount_);
        IProvider(pool)._withdrawProvider(toPay, 0);
        IProvider(pool)._sendUnderlying(msg.sender, toPay);
    }


    function buyBond(
        uint256 principalAmount_,
        uint256 minGain_,
        uint256 deadline_,
        uint16 forDays_
    )
      external override
    {
        _beforeProviderOp();

        require(
          false == IController(controller).PAUSED_BUY_SENIOR_BOND(),
          "SY: buyBond paused"
        );

        require(
          this.currentTime() <= deadline_,
          "SY: buyBond deadline"
        );

        require(
            0 < forDays_ && forDays_ <= IController(controller).BOND_LIFE_MAX(),
            "SY: buyBond forDays"
        );

        uint256 gain = this.bondGain(principalAmount_, forDays_);

        require(
          gain >= minGain_,
          "SY: buyBond minGain"
        );

        require(
          gain > 0,
          "SY: buyBond gain 0"
        );

        require(
          gain < this.underlyingLoanable(),
          "SY: buyBond underlyingLoanable"
        );

        uint256 issuedAt = this.currentTime();



        IProvider(pool)._takeUnderlying(msg.sender, principalAmount_);
        IProvider(pool)._depositProvider(principalAmount_, 0);

        SeniorBond memory b =
            SeniorBond(
                principalAmount_,
                gain,
                issuedAt,
                uint256(1 days) * uint256(forDays_) + issuedAt,
                false
            );

        _mintBond(msg.sender, b);
    }


    function buyJuniorBond(
      uint256 tokenAmount_,
      uint256 maxMaturesAt_,
      uint256 deadline_
    )
      external override
    {
        uint256 maturesAt = 1 + abond.maturesAt / 1e18;

        require(
          this.currentTime() <= deadline_,
          "SY: buyJuniorBond deadline"
        );

        require(
          maturesAt <= maxMaturesAt_,
          "SY: buyJuniorBond maxMaturesAt"
        );

        JuniorBond memory jb = JuniorBond(
          tokenAmount_,
          maturesAt
        );



        _takeTokens(msg.sender, tokenAmount_);
        _mintJuniorBond(msg.sender, jb);


        if (this.currentTime() >= maturesAt) {
            JuniorBondsAt memory jBondsAt = juniorBondsMaturingAt[jb.maturesAt];

            if (jBondsAt.price == 0) {
                _liquidateJuniorsAt(jb.maturesAt);
            } else {

                _burn(address(this), jb.tokens); 
                underlyingLiquidatedJuniors += jb.tokens * jBondsAt.price / 1e18;
                _unaccountJuniorBond(jb);
            }
            return this.redeemJuniorBond(juniorBondId);
        }
    }


    function redeemBond(
      uint256 bondId_
    )
      external override
    {
        _beforeProviderOp();

        require(
            this.currentTime() >= seniorBonds[bondId_].maturesAt,
            "SY: redeemBond not matured"
        );


        address payTo = IBond(seniorBond).ownerOf(bondId_);
        uint256 payAmnt = seniorBonds[bondId_].gain + seniorBonds[bondId_].principal;
        uint256 fee = MathUtils.fractionOf(seniorBonds[bondId_].gain, IController(controller).FEE_REDEEM_SENIOR_BOND());
        payAmnt -= fee;



        if (seniorBonds[bondId_].liquidated == false) {
            seniorBonds[bondId_].liquidated = true;
            _unaccountBond(seniorBonds[bondId_]);
        }


        IBond(seniorBond).burn(bondId_);
        delete seniorBonds[bondId_];

        IProvider(pool)._withdrawProvider(payAmnt, fee);
        IProvider(pool)._sendUnderlying(payTo, payAmnt);
    }


    function redeemJuniorBond(uint256 jBondId_)
        external override
    {
        _beforeProviderOp();

        JuniorBond memory jb = juniorBonds[jBondId_];
        require(
            jb.maturesAt <= this.currentTime(),
            "SY: redeemJuniorBond maturesAt"
        );

        JuniorBondsAt memory jBondsAt = juniorBondsMaturingAt[jb.maturesAt];


        address payTo = IBond(juniorBond).ownerOf(jBondId_);
        uint256 payAmnt = jBondsAt.price * jb.tokens / 1e18;



        _burnJuniorBond(jBondId_);
        IProvider(pool)._withdrawProvider(payAmnt, 0);
        IProvider(pool)._sendUnderlying(payTo, payAmnt);
        underlyingLiquidatedJuniors -= payAmnt;
    }


    function providerRatePerDay()
      external view virtual override
    returns (uint256)
    {
        return MathUtils.min(
          IController(controller).BOND_MAX_RATE_PER_DAY(),
          IYieldOracle(IController(controller).oracle()).consult(1 days)
        );
    }


    function bondGain(uint256 principalAmount_, uint16 forDays_)
      external view override
    returns (uint256)
    {
        return IBondModel(IController(controller).bondModel()).gain(address(this), principalAmount_, forDays_);
    }





    function currentTime()
      public view virtual override
    returns (uint256)
    {

        return block.timestamp;
    }


    function price()
      public view override
    returns (uint256)
    {
        uint256 ts = totalSupply();
        return (ts == 0) ? 1e18 : (this.underlyingJuniors() * 1e18) / ts;
    }

    function underlyingTotal()
      public view virtual override
    returns(uint256)
    {
      return IProvider(pool).underlyingBalance() - IProvider(pool).underlyingFees() - underlyingLiquidatedJuniors;
    }

    function underlyingJuniors()
      public view virtual override
    returns (uint256)
    {
        return this.underlyingTotal() - abond.principal - this.abondPaid();
    }

    function underlyingLoanable()
      public view virtual override
    returns (uint256)
    {

        return this.underlyingTotal() - abond.principal - abond.gain - (tokensInJuniorBonds * this.price() / 1e18);
    }

    function abondGain()
      public view override
    returns (uint256)
    {
        return abond.gain;
    }

    function abondPaid()
      public view override
    returns (uint256)
    {
        uint256 ts = this.currentTime() * 1e18;
        if (ts <= abond.issuedAt || (abond.maturesAt <= abond.issuedAt)) {
          return 0;
        }

        uint256 d = abond.maturesAt - abond.issuedAt;
        return (this.abondGain() * MathUtils.min(ts - abond.issuedAt, d)) / d;
    }

    function abondDebt()
      public view override
    returns (uint256)
    {
        return this.abondGain() - this.abondPaid();
    }





    function _beforeProviderOp() internal {



      for (uint256 i = juniorBondsMaturitiesPrev; i < juniorBondsMaturities.length; i++) {
          if (this.currentTime() >= juniorBondsMaturities[i]) {
              _liquidateJuniorsAt(juniorBondsMaturities[i]);
              juniorBondsMaturitiesPrev = i + 1;
          } else {
              break;
          }
      }
    }

    function _liquidateJuniorsAt(uint256 timestamp_)
      internal
    {
        JuniorBondsAt storage jBondsAt = juniorBondsMaturingAt[timestamp_];

        require(
          jBondsAt.tokens > 0,
          "SY: nothing to liquidate"
        );

        require(
          jBondsAt.price == 0,
          "SY: already liquidated"
        );

        jBondsAt.price = this.price();



        underlyingLiquidatedJuniors += jBondsAt.tokens * jBondsAt.price / 1e18;
        _burn(address(this), jBondsAt.tokens); 
        tokensInJuniorBonds -= jBondsAt.tokens;
    }


    function unaccountBonds(uint256[] memory bondIds_) public override {
      for (uint256 f = 0; f < bondIds_.length; f++) {
        if (
            this.currentTime() > seniorBonds[bondIds_[f]].maturesAt &&
            seniorBonds[bondIds_[f]].liquidated == false
        ) {
            seniorBonds[bondIds_[f]].liquidated = true;
            _unaccountBond(seniorBonds[bondIds_[f]]);
        }
      }
    }

    function _mintBond(address to_, SeniorBond memory bond_)
      internal
    {
        require(
          seniorBondId < uint256(-1),
          "SY: _mintBond"
        );

        seniorBondId++;
        seniorBonds[seniorBondId] = bond_;
        _accountBond(bond_);
        IBond(seniorBond).mint(to_, seniorBondId);
    }




    function _accountBond(SeniorBond memory b_)
      internal
    {
        uint256 _now = this.currentTime() * 1e18;

        uint256 newDebt = this.abondDebt() + b_.gain;

        uint256 newMaturesAt = (abond.maturesAt * this.abondDebt() + b_.maturesAt * 1e18 * b_.gain) / newDebt;


        uint256 newIssuedAt = newMaturesAt.sub(uint256(1) + ((abond.gain + b_.gain) * (newMaturesAt - _now)) / newDebt, "SY: liquidate some seniorBonds");

        abond = SeniorBond(
          abond.principal + b_.principal,
          abond.gain + b_.gain,
          newIssuedAt,
          newMaturesAt,
          false
        );
    }




    function _unaccountBond(SeniorBond memory b_)
      internal
    {
        uint256 now_ = this.currentTime() * 1e18;

        if ((now_ >= abond.maturesAt)) {


          abond = SeniorBond(
            abond.principal - b_.principal,
            abond.gain - b_.gain,
            now_ - (abond.maturesAt - abond.issuedAt),
            now_,
            false
          );

          return;
        }


        uint256 newIssuedAt = abond.maturesAt.sub(uint256(1) + (abond.gain - b_.gain) * (abond.maturesAt - now_) / this.abondDebt(), "SY: liquidate some seniorBonds");

        abond = SeniorBond(
          abond.principal - b_.principal,
          abond.gain - b_.gain,
          newIssuedAt,
          abond.maturesAt,
          false
        );
    }

    function _mintJuniorBond(address to_, JuniorBond memory jb_)
      internal
    {
        require(
          juniorBondId < uint256(-1),
          "SY: _mintJuniorBond"
        );

        juniorBondId++;
        juniorBonds[juniorBondId] = jb_;

        _accountJuniorBond(jb_);
        IBond(juniorBond).mint(to_, juniorBondId);
    }

    function _accountJuniorBond(JuniorBond memory jb_)
      internal
    {
        tokensInJuniorBonds += jb_.tokens;

        JuniorBondsAt storage jBondsAt = juniorBondsMaturingAt[jb_.maturesAt];
        uint256 tmp;

        if (jBondsAt.tokens == 0 && this.currentTime() < jb_.maturesAt) {
          juniorBondsMaturities.push(jb_.maturesAt);
          for (uint256 i = juniorBondsMaturities.length - 1; i >= MathUtils.max(1, juniorBondsMaturitiesPrev); i--) {
            if (juniorBondsMaturities[i] > juniorBondsMaturities[i - 1]) {
              break;
            }
            tmp = juniorBondsMaturities[i - 1];
            juniorBondsMaturities[i - 1] = juniorBondsMaturities[i];
            juniorBondsMaturities[i] = tmp;
          }
        }

        jBondsAt.tokens += jb_.tokens;
    }

    function _burnJuniorBond(uint256 bondId_) internal {




        IBond(juniorBond).burn(bondId_);
    }

    function _unaccountJuniorBond(JuniorBond memory jb_) internal {
        tokensInJuniorBonds -= jb_.tokens;
        JuniorBondsAt storage jBondsAt = juniorBondsMaturingAt[jb_.maturesAt];
        jBondsAt.tokens -= jb_.tokens;
    }

    function _takeTokens(address _from, uint256 _amount) internal {

        require(
            transferFrom(_from, address(this), _amount),
            "SY: _takeTokens transferFrom"
        );
    }



}

pragma solidity =0.6.10;
pragma experimental ABIEncoderV2;

import {WETH9} from "../canonical-weth/WETH9.sol";
import {ReentrancyGuard} from "../../packages/oz/ReentrancyGuard.sol";
import {SafeERC20} from "../../packages/oz/SafeERC20.sol";
import {ERC20Interface} from "../../interfaces/ERC20Interface.sol";
import {Actions} from "../../libs/Actions.sol";
import {Controller} from "../../Controller.sol";


contract PayableProxyController is ReentrancyGuard {
    WETH9 public weth;
    Controller public controller;
    using SafeERC20 for ERC20Interface;

    constructor(
        address _controller,
        address _marginPool,
        address payable _weth
    ) public {
        controller = Controller(_controller);
        weth = WETH9(_weth);
        ERC20Interface(address(weth)).safeApprove(_marginPool, uint256(-1));
    }


    fallback() external payable {
        require(msg.sender == address(weth), "PayableProxyController: Cannot receive ETH");
    }


    function operate(Actions.ActionArgs[] memory _actions, address payable sendEthTo) external payable nonReentrant {

        if (msg.value != 0) {
            weth.deposit{value: msg.value}();
        }


        for (uint256 i = 0; i < _actions.length; i++) {
            Actions.ActionArgs memory action = _actions[i];


            if (action.owner != address(0)) {
                require(
                    (msg.sender == action.owner) || (controller.isOperator(action.owner, msg.sender)),
                    "PayableProxyController: cannot execute action "
                );
            }
        }

        controller.operate(_actions);


        uint256 remainingWeth = weth.balanceOf(address(this));
        if (remainingWeth != 0) {
            require(sendEthTo != address(0), "PayableProxyController: cannot send ETH to address zero");

            weth.withdraw(remainingWeth);

            sendEthTo.transfer(remainingWeth);
        }
    }
}

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/Address.sol";
import "@openzeppelin/contracts/utils/Context.sol";
import "@openzeppelin/contracts/utils/math/SafeMath.sol";
import "@uniswap/v2-core/contracts/interfaces/IUniswapV2Factory.sol";
import "@uniswap/v2-core/contracts/interfaces/IUniswapV2Pair.sol";
import "@uniswap/v2-periphery/contracts/interfaces/IUniswapV2Router01.sol";
import "@uniswap/v2-periphery/contracts/interfaces/IUniswapV2Router02.sol";


contract AllCoinsYieldCapital is Context, IERC20, Ownable {
    using SafeMath for uint256;
    using Address for address;


    string private _name = "AllCoinsYieldCapital";
    string private _symbol = "ACYC";
    uint8 private _decimals = 18;


    uint256 private constant MAX = ~uint256(0);
    uint256 private _totalTokenSupply = 1 * 10**12 * 10**_decimals;
    uint256 private _totalReflections = (MAX - (MAX % _totalTokenSupply));
    uint256 private _totalTaxesReflectedToHodlers;
    uint256 private _totalTaxesSentToTreasury;
    mapping(address => uint256) private _reflectionsOwned;
    mapping(address => mapping(address => uint256)) private _allowances;


    address payable public _treasuryAddress;
    uint256 private _currentTaxForReflections = 10; 
    uint256 private _currentTaxForTreasury = 10; 
    uint256 public _fixedTaxForReflections = 10; 
    uint256 public _fixedTaxForTreasury = 10; 


    mapping(address => bool) private _isExcludedFromTaxes;




    address private uniDefault = 0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D;
    IUniswapV2Router02 public immutable uniswapV2Router;
    bool private _inSwap = false;
    address public immutable uniswapV2Pair;


    uint256 private _minimumTokensToSwap = 10 * 10**3 * 10**_decimals;

    modifier lockTheSwap() {
        _inSwap = true;
        _;
        _inSwap = false;
    }

    constructor(address payable treasuryAddress, address router) {
        require(
            (treasuryAddress != address(0)),
            "Give me the treasury address"
        );
        _treasuryAddress = treasuryAddress;
        _reflectionsOwned[_msgSender()] = _totalReflections;


        if (router == address(0)) {
            router = uniDefault;
        }
        IUniswapV2Router02 _uniswapV2Router = IUniswapV2Router02(router);


        address _uniswapV2Pair = IUniswapV2Factory(_uniswapV2Router.factory())
            .createPair(address(this), _uniswapV2Router.WETH());
        uniswapV2Pair = _uniswapV2Pair;
        uniswapV2Router = _uniswapV2Router;


        _isExcludedFromTaxes[owner()] = true;
        _isExcludedFromTaxes[address(this)] = true;
        _isExcludedFromTaxes[_treasuryAddress] = true;

        emit Transfer(address(0), _msgSender(), _totalTokenSupply);
    }


    receive() external payable {
        return;
    }


    function setTreasuryAddress(address payable treasuryAddress) external {
        require(_msgSender() == _treasuryAddress, "You cannot call this");
        require(
            (treasuryAddress != address(0)),
            "Give me the treasury address"
        );
        address _previousTreasuryAddress = _treasuryAddress;
        _treasuryAddress = treasuryAddress;
        _isExcludedFromTaxes[treasuryAddress] = true;
        _isExcludedFromTaxes[_previousTreasuryAddress] = false;
    }


    function excludeFromTaxes(address account, bool excluded)
        external
        onlyOwner
    {
        _isExcludedFromTaxes[account] = excluded;
    }


    function setReflectionsTax(uint256 tax) external onlyOwner {

        require(tax >= 0 && tax <= 10, "ERC20: tax out of band");
        _currentTaxForReflections = tax;
        _fixedTaxForReflections = tax;
    }

    function setTreasuryTax(uint256 tax) external onlyOwner {

        require(tax >= 0 && tax <= 10, "ERC20: tax out of band");
        _currentTaxForTreasury = tax;
        _fixedTaxForTreasury = tax;
    }


    function manualSend() external onlyOwner {
        uint256 _contractETHBalance = address(this).balance;
        _sendETHToTreasury(_contractETHBalance);
    }

    function manualSwap() external onlyOwner {
        uint256 _contractBalance = balanceOf(address(this));
        _swapTokensForEth(_contractBalance);
    }



    function transfer(address recipient, uint256 amount)
        public
        override
        returns (bool)
    {
        _transfer(_msgSender(), recipient, amount);
        return true;
    }

    function approve(address spender, uint256 amount)
        public
        override
        returns (bool)
    {
        _approve(_msgSender(), spender, amount);
        return true;
    }


    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) public override returns (bool) {
        _transfer(sender, recipient, amount);
        _approve(
            sender,
            _msgSender(),
            _allowances[sender][_msgSender()].sub(
                amount,
                "ERC20: transfer amount exceeds allowance"
            )
        );
        return true;
    }

    function increaseAllowance(address spender, uint256 addedValue)
        public
        virtual
        returns (bool)
    {
        _approve(
            _msgSender(),
            spender,
            _allowances[_msgSender()][spender].add(addedValue)
        );
        return true;
    }

    function decreaseAllowance(address spender, uint256 subtractedValue)
        public
        virtual
        returns (bool)
    {
        _approve(
            _msgSender(),
            spender,
            _allowances[_msgSender()][spender].sub(
                subtractedValue,
                "ERC20: decreased allowance below zero"
            )
        );
        return true;
    }

    function name() public view returns (string memory) {
        return _name;
    }

    function symbol() public view returns (string memory) {
        return _symbol;
    }

    function decimals() public view returns (uint8) {
        return _decimals;
    }

    function totalSupply() public view override returns (uint256) {
        uint256 currentRate = _getRate();
        return _totalReflections.div(currentRate);
    }

    function isExcludedFromTaxes(address account) public view returns (bool) {
        return _isExcludedFromTaxes[account];
    }

    function totalTaxesSentToReflections() public view returns (uint256) {
        return tokensFromReflection(_totalTaxesReflectedToHodlers);
    }

    function totalTaxesSentToTreasury() public view returns (uint256) {
        return tokensFromReflection(_totalTaxesSentToTreasury);
    }

    function getETHBalance() public view returns (uint256 balance) {
        return address(this).balance;
    }

    function allowance(address owner, address spender)
        public
        view
        override
        returns (uint256)
    {
        return _allowances[owner][spender];
    }

    function balanceOf(address account) public view override returns (uint256) {
        return tokensFromReflection(_reflectionsOwned[account]);
    }

    function reflectionFromToken(
        uint256 amountOfTokens,
        bool deductTaxForReflections
    ) public view returns (uint256) {
        require(
            amountOfTokens <= _totalTokenSupply,
            "Amount must be less than supply"
        );
        if (!deductTaxForReflections) {
            (uint256 reflectionsToDebit, , , ) = _getValues(amountOfTokens);
            return reflectionsToDebit;
        } else {
            (, uint256 reflectionsToCredit, , ) = _getValues(amountOfTokens);
            return reflectionsToCredit;
        }
    }

    function tokensFromReflection(uint256 amountOfReflections)
        public
        view
        returns (uint256)
    {
        require(
            amountOfReflections <= _totalReflections,
            "ERC20: Amount too large"
        );
        uint256 currentRate = _getRate();
        return amountOfReflections.div(currentRate);
    }

    function _approve(
        address owner,
        address spender,
        uint256 amount
    ) private {
        require(owner != address(0), "ERC20: approve from 0 address");
        require(spender != address(0), "ERC20: approve to 0 address");
        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }





    function _transfer(
        address sender,
        address recipient,
        uint256 amountOfTokens
    ) private {
        require(sender != address(0), "ERC20: transfer from 0 address");
        require(recipient != address(0), "ERC20: transfer to 0 address");
        require(amountOfTokens > 0, "ERC20: Transfer more than zero");



        bool takeFee = true;
        if (_isExcludedFromTaxes[sender] || _isExcludedFromTaxes[recipient]) {
            takeFee = false;
        }



        bool buySide = false;
        if (sender == address(uniswapV2Pair)) {
            buySide = true;
        }


        if (!takeFee) {
            _setNoFees();
        } else if (buySide) {
            _setBuySideFees();
        } else {
            _setSellSideFees();
        }


        _tokenTransfer(sender, recipient, amountOfTokens);


        _restoreAllFees();
    }


    function _tokenTransfer(
        address sender,
        address recipient,
        uint256 amountOfTokens
    ) private {









        if (sender == _treasuryAddress && recipient == address(this)) {
            _manualReflect(amountOfTokens);
            return;
        }



        (
            uint256 reflectionsToDebit, 
            uint256 reflectionsToCredit, 
            uint256 reflectionsToRemove, 
            uint256 reflectionsForTreasury 
        ) = _getValues(amountOfTokens);


        _takeTreasuryTax(reflectionsForTreasury);
        _takeReflectionTax(reflectionsToRemove);



        uint256 contractTokenBalance = balanceOf(address(this));
        bool overMinTokenBalance = contractTokenBalance >= _minimumTokensToSwap;
        if (!_inSwap && overMinTokenBalance && reflectionsForTreasury != 0) {
            _swapTokensForEth(contractTokenBalance);
        }
        uint256 contractETHBalance = address(this).balance;
        if (contractETHBalance > 0) {
            _sendETHToTreasury(address(this).balance);
        }




        _reflectionsOwned[sender] = _reflectionsOwned[sender].sub(
            reflectionsToDebit
        );
        _reflectionsOwned[recipient] = _reflectionsOwned[recipient].add(
            reflectionsToCredit
        );


        emit Transfer(sender, recipient, reflectionsToCredit.div(_getRate()));
    }



    function _manualReflect(uint256 amountOfTokens) private {
        uint256 currentRate = _getRate();
        uint256 amountOfReflections = amountOfTokens.mul(currentRate);





        _reflectionsOwned[_treasuryAddress] = _reflectionsOwned[
            _treasuryAddress
        ].sub(amountOfReflections);
        _totalReflections = _totalReflections.sub(amountOfReflections);
    }














    function _takeTreasuryTax(uint256 reflectionsForTreasury) private {
        _reflectionsOwned[address(this)] = _reflectionsOwned[address(this)].add(
            reflectionsForTreasury
        );
        _totalTaxesSentToTreasury = _totalTaxesSentToTreasury.add(
            reflectionsForTreasury
        );
    }










    function _takeReflectionTax(uint256 reflectionsToRemove) private {
        _totalReflections = _totalReflections.sub(reflectionsToRemove);
        _totalTaxesReflectedToHodlers = _totalTaxesReflectedToHodlers.add(
            reflectionsToRemove
        );
    }




    function _swapTokensForEth(uint256 tokenAmount) private lockTheSwap {

        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = uniswapV2Router.WETH();

        _approve(address(this), address(uniswapV2Router), tokenAmount);


        uniswapV2Router.swapExactTokensForETHSupportingFeeOnTransferTokens(
            tokenAmount,
            0, 
            path,
            address(_treasuryAddress),
            block.timestamp
        );
    }

    function _sendETHToTreasury(uint256 amount) private {
        _treasuryAddress.transfer(amount);
    }



    function _setBuySideFees() private {
        _currentTaxForReflections = _fixedTaxForReflections;
        _currentTaxForTreasury = 0;
    }



    function _setSellSideFees() private {
        _currentTaxForReflections = 0;
        _currentTaxForTreasury = _fixedTaxForTreasury;
    }


    function _setNoFees() private {
        _currentTaxForReflections = 0;
        _currentTaxForTreasury = 0;
    }






    function _restoreAllFees() private {
        _currentTaxForReflections = _fixedTaxForReflections;
        _currentTaxForTreasury = _fixedTaxForTreasury;
    }




    function _getValues(uint256 amountOfTokens)
        private
        view
        returns (
            uint256,
            uint256,
            uint256,
            uint256
        )
    {


        (
            uint256 tokensToTransfer,
            uint256 tokensForReflections,
            uint256 tokensForTreasury
        ) = _getTokenValues(amountOfTokens);



        uint256 currentRate = _getRate();
        uint256 reflectionsTotal = amountOfTokens.mul(currentRate);
        uint256 reflectionsToTransfer = tokensToTransfer.mul(currentRate);
        uint256 reflectionsToRemove = tokensForReflections.mul(currentRate);
        uint256 reflectionsForTreasury = tokensForTreasury.mul(currentRate);

        return (
            reflectionsTotal,
            reflectionsToTransfer,
            reflectionsToRemove,
            reflectionsForTreasury
        );
    }




    function _getRate() private view returns (uint256) {
        return _totalReflections.div(_totalTokenSupply);
    }






    function _getTokenValues(uint256 amountOfTokens)
        private
        view
        returns (
            uint256,
            uint256,
            uint256
        )
    {
        uint256 tokensForReflections = amountOfTokens
            .mul(_currentTaxForReflections)
            .div(100);
        uint256 tokensForTreasury = amountOfTokens
            .mul(_currentTaxForTreasury)
            .div(100);
        uint256 tokensToTransfer = amountOfTokens.sub(tokensForReflections).sub(
            tokensForTreasury
        );
        return (tokensToTransfer, tokensForReflections, tokensForTreasury);
    }
}

pragma solidity ^0.5.16;

import "./CToken.sol";
import "./ErrorReporter.sol";
import "./Exponential.sol";
import "./PriceOracle.sol";
import "./ComptrollerInterface.sol";
import "./ComptrollerStorage.sol";
import "./Unitroller.sol";
import "./Governance/Comp.sol";


contract Comptroller is ComptrollerV5Storage, ComptrollerInterface, ComptrollerErrorReporter, Exponential {

    event MarketListed(CToken cToken);


    event MarketEntered(CToken cToken, address account);


    event MarketExited(CToken cToken, address account);


    event NewCloseFactor(uint oldCloseFactorMantissa, uint newCloseFactorMantissa);


    event NewCollateralFactor(CToken cToken, uint oldCollateralFactorMantissa, uint newCollateralFactorMantissa);


    event NewLiquidationIncentive(uint oldLiquidationIncentiveMantissa, uint newLiquidationIncentiveMantissa);


    event NewPriceOracle(PriceOracle oldPriceOracle, PriceOracle newPriceOracle);


    event NewPauseGuardian(address oldPauseGuardian, address newPauseGuardian);


    event ActionPaused(string action, bool pauseState);


    event ActionPaused(CToken cToken, string action, bool pauseState);


    event CompSpeedUpdated(CToken indexed cToken, uint newSpeed);


    event DistributedSupplierComp(CToken indexed cToken, address indexed supplier, uint compDelta, uint compSupplyIndex);


    event DistributedBorrowerComp(CToken indexed cToken, address indexed borrower, uint compDelta, uint compBorrowIndex);


    event NewBorrowCap(CToken indexed cToken, uint newBorrowCap);


    event NewBorrowCapGuardian(address oldBorrowCapGuardian, address newBorrowCapGuardian);


    event NewSupplyCap(CToken indexed cToken, uint newSupplyCap);


    event NewSupplyCapGuardian(address oldSupplyCapGuardian, address newSupplyCapGuardian);


    event NewCTokenVersion(CToken cToken, Version oldVersion, Version newVersion);


    uint public constant compClaimThreshold = 0.001e18;


    uint224 public constant compInitialIndex = 1e36;


    uint internal constant collateralFactorMaxMantissa = 0.9e18; 

    constructor() public {
        admin = msg.sender;
    }




    function getAssetsIn(address account) external view returns (CToken[] memory) {
        CToken[] memory assetsIn = accountAssets[account];

        return assetsIn;
    }


    function checkMembership(address account, CToken cToken) external view returns (bool) {
        return markets[address(cToken)].accountMembership[account];
    }


    function enterMarkets(address[] memory cTokens) public returns (uint[] memory) {
        uint len = cTokens.length;

        uint[] memory results = new uint[](len);
        for (uint i = 0; i < len; i++) {
            Error result = addToMarketInternal(CToken(cTokens[i]), msg.sender);
            if (result == Error.NO_ERROR && markets[cTokens[i]].version == Version.COLLATERALCAP) {
                CCollateralCapErc20Interface(cTokens[i]).registerCollateral(msg.sender);
            }
            results[i] = uint(result);
        }

        return results;
